import Header from "../../components/Header/Header";
import classes from "./Chat.module.css";
import ChatForm from "../../components/Chat/ChatForm";
import React, { useState, useEffect, useRef } from "react";
import ChatMessage from "../../components/Chat/ChatMessage";
import { useParams } from "react-router-dom";

const Chat = (props) => {
  const [messages, setMessages] = useState([]);
  const params = useParams();
  const ws = useRef(null);
  const storedChat = {};

  console.log("CHAT RERENDERED");

  const submitMessageHandler = (data) => {
    ws.current.send(JSON.stringify(data));
  };

  useEffect(() => {
    // Fetch data
    const fetchData = async () => {
      try {
        const res = await fetch(`/channel/${params.id}`, {
          headers: {
            Authorization: "Bearer " + props.token,
          },
        });

        const data = await res.json();
        console.log(data);

        setMessages(data.messages);
      } catch (err) {
        console.log(err);
      }
    };

    fetchData();

    ws.current = new WebSocket("ws://localhost:8080");

    ws.current.onopen = () => {
      console.log("Connection Opened");
      const data = {
        message: "Hello Server",
        chatId: "",
        sender: "",
        users: [],
      };
      ws.current.send(JSON.stringify(data));
    };

    ws.current.onmessage = (message) => {
      console.log(message);
    };

    ws.current.onclose = () => {};
    ws.current.onerror = () => {};

    // Cleanup function
    return () => {
      ws.current.close();
    };
  }, [props.token, params.id]);

  return (
    <div className={classes["container"]}>
      <Header
        title="Bob"
        avatar="https://animedao.to/images/call-of-the-night.jpg"
        tabBar={false}
      ></Header>
      <div className={classes["messages-wrapper"]}>
        <ol className={classes["messages"]}>
          {messages.map((item) => (
            <ChatMessage
              key={item._id}
              message={item.message}
              user={item.senderName}
              avatar="https://animedao.to/images/call-of-the-night.jpg"
            ></ChatMessage>
          ))}
          <div className={classes["messages-spacer"]}></div>
        </ol>
      </div>
      <ChatForm submitMessage={submitMessageHandler}></ChatForm>
    </div>
  );
};

export default Chat;
